If interviewer has issue with computing sum or checking for similarity in elemets in given region, use prefix sum to precompute the uniqueness in matrix. Compute the similarity in constant time  for deciding the compression.
 ` public class QuadTree
{
    public static QuadTreeNode BuildQuadTree(int[,] matrix, int x, int y, int size, int[,] prefixSum)
    {
        if (size == 1) return new QuadTreeNode(matrix[x, y]); // Base case

        if (IsUniformUsingPrefixSum(prefixSum, x, y, size, matrix))
            return new QuadTreeNode(matrix[x, y]); // Return compressed node

        int half = size / 2;
        return new QuadTreeNode(new QuadTreeNode[]
        {
            BuildQuadTree(matrix, x, y, half, prefixSum),            // Top-left
            BuildQuadTree(matrix, x, y + half, half, prefixSum),     // Top-right
            BuildQuadTree(matrix, x + half, y, half, prefixSum),     // Bottom-left
            BuildQuadTree(matrix, x + half, y + half, half, prefixSum) // Bottom-right
        });
    }

    private static bool IsUniformUsingPrefixSum(int[,] prefixSum, int x, int y, int size, int[,] matrix)
    {
        // Calculate the sum of the submatrix (x, y) to (x + size - 1, y + size - 1)
        int total = prefixSum[x + size - 1, y + size - 1];
        if (x > 0) total -= prefixSum[x - 1, y + size - 1];
        if (y > 0) total -= prefixSum[x + size - 1, y - 1];
        if (x > 0 && y > 0) total += prefixSum[x - 1, y - 1];

        int expectedSum = matrix[x, y] * size * size;
        return total == expectedSum; // If sum matches, the submatrix is uniform
    }

    public static int[,] ComputePrefixSum(int[,] matrix)
    {
        int n = matrix.GetLength(0);
        int[,] prefixSum = new int[n, n];

        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < n; j++)
            {
                prefixSum[i, j] = matrix[i, j];
                if (i > 0) prefixSum[i, j] += prefixSum[i - 1, j];
                if (j > 0) prefixSum[i, j] += prefixSum[i, j - 1];
                if (i > 0 && j > 0) prefixSum[i, j] -= prefixSum[i - 1, j - 1];
            }
        }
        return prefixSum;
    }
}`
